def shortestPathAllKeys(grid):
    R, C = len(grid), len(grid[0])
    q = []
    target = 0
    for r in range(R):
        for c in range(C):
            if grid[r][c] == '@':
                q = [(r, c, 0, 0)]
            elif grid[r][c] in 'abcdef':
                target |= 1 << (ord(grid[r][c]) - ord('a'))
    seen = set([(q[0][0], q[0][1], 0)])
    for r, c, keys, d in q:
        if keys == target: return d
        for dr, dc in ((0,1),(0,-1),(1,0),(-1,0)):
            nr, nc = r + dr, c + dc
            if 0 <= nr < R and 0 <= nc < C and grid[nr][nc] != '#':
                char = grid[nr][nc]
                if char in 'ABCDEF' and not (keys & (1 << (ord(char) - ord('A')))):
                    continue
                nkeys = keys
                if char in 'abcdef':
                    nkeys |= 1 << (ord(char) - ord('a'))
                if (nr, nc, nkeys) not in seen:
                    seen.add((nr, nc, nkeys))
                    q.append((nr, nc, nkeys, d + 1))
    return -1

